import json

lines = open('ios_crash.ips').readlines()
metadata = json.loads(lines[0])
crash = json.loads(''.join(lines[1:]))

# Check for any additional fields that might contain exception info
for key in ['asiBacktraces', 'lastExceptionType', 'lastExceptionMessage', 
            'asi', 'nsexception', 'lastException', 'exceptionExtra']:
    if key in crash:
        print(f"{key}: {crash[key]}")

# Check termination details
print(f"\ntermination: {crash.get('termination')}")

# Check if there's a 'storeInfo' or other metadata
for key in ['modelCode', 'coalitionName', 'isCorpse', 'storeInfo']:
    if key in crash:
        print(f"{key}: {crash[key]}")

# Check all top-level keys for anything useful
print("\n=== All top-level keys ===")
for k in sorted(crash.keys()):
    v = crash[k]
    if isinstance(v, (str, int, float, bool)):
        print(f"  {k}: {v}")
    elif isinstance(v, dict) and len(str(v)) < 200:
        print(f"  {k}: {v}")
    else:
        tp = type(v).__name__
        if isinstance(v, list):
            print(f"  {k}: [{tp}, {len(v)} items]")
        else:
            print(f"  {k}: [{tp}]")
